<template>
	<AppShell active="adoption"><view class="page-container"><view class="page-heading"><view><text class="page-title">发布领养信息</text><text class="page-subtitle">请真实描述健康情况与领养要求</text></view></view><view class="card panel"><view class="form-grid"><label v-for="f in fields" :key="f.key" class="form-field" :class="{full:f.full}"><text>{{f.label}}</text><textarea v-if="f.full" v-model="form[f.key]"/><input v-else v-model="form[f.key]"/></label></view><view class="button-row"><button class="action-button" :loading="saving" @click="save">发布</button></view></view></view></AppShell>
</template>
<script>
import AppShell from '../../components/AppShell.vue';import{adoptionApi}from'../../api'
export default{components:{AppShell},data(){return{saving:false,form:{name:'',species:'',breed:'',age_text:'',gender:'',city:'',description:'',health_status:'',requirements:'',cover_image:''},fields:[{key:'name',label:'名字'},{key:'species',label:'物种'},{key:'breed',label:'品种'},{key:'age_text',label:'年龄'},{key:'gender',label:'性别'},{key:'city',label:'城市'},{key:'cover_image',label:'封面 URL',full:true},{key:'description',label:'详细介绍',full:true},{key:'health_status',label:'健康情况',full:true},{key:'requirements',label:'领养要求',full:true}]}},methods:{async save(){if(['name','species','city','description'].some(k=>!this.form[k]))return uni.showToast({title:'请填写必填信息',icon:'none'});this.saving=true;try{const item=await adoptionApi.create(this.form);uni.showToast({title:'领养信息已发布'});setTimeout(()=>uni.redirectTo({url:`/pages/adoption/detail?id=${item.id}`}),400)}catch(e){}finally{this.saving=false}}}}
</script>
